genTy :: Int -> QC.Gen Ty
genTy sz
  | sz <= 1   = QC.elements [ voidTy, unitTy ]
  | otherwise = QC.oneof [ genArr, genProd, genSum ]
     where
       sz' = sz `div` 2
       genArr  = (:->) <$> genTy sz' <*> genTy sz'
       genProd = Prod  <$> QC.listOf (genTy sz')
       genSum  = Sum   <$> QC.listOf (genTy sz')


-- | Produce a list of types smaller than the argument
--
-- >>> map oneline (shrinkTy (boolTy :-> unitTy))
-- ["0","1","2","1","0 -> 1","1 -> 1","1 -> 1"]

shrinkTy :: Ty -> [Ty]
shrinkTy (a :-> b) = voidTy : unitTy : shrinkTwo (:->) a b
shrinkTy (Prod ts) = [Prod ts' | ts' <- shrink ts]
shrinkTy (Sum ts)  = [Sum ts' | ts' <- shrink ts]

-- * Arbitrary instance for terms

instance QC.Arbitrary Tm where
  arbitrary :: QC.Gen Tm
  arbitrary = QC.sized (genTm 0)

  shrink :: Tm -> [Tm]
  shrink = shrinkTm


-- | Variable names used when generating lambda binders
varNames :: [String]
varNames = ["x", "y", "z", "w", "a", "b", "c", "d"] ++ [ "x" ++ show n | n <- [0 .. ]]

-- | Select from the first 'n' variable names, fails if n <= 0
-- 
-- >>> QC.sample' (genVar 3)

-- | Select uniformly from the first @n@ variable names; fails if @n <= 0@
genVar n = QC.elements (take n varNames)

-- | Generate a term of size 'sz' with 'vars' in scope
--
-- >>> fmap oneline <$> fmap fst <$> QC.sample' (genPat 0 3)

genPatVar :: Int -> QC.Gen (Tm, Int)
genPatVar vars = pure (Var (varNames !! vars), vars+1)

genPat :: Int -> Int -> QC.Gen (Tm, Int)
genPat vars sz
  | sz <= 1 = QC.oneof [genPatVar vars, pure (Pair [], vars)]
  | otherwise = QC.oneof [
         genPatVar vars
       , pure (Pair [], vars)
       , do (p1, vars1) <- genPat vars sz'
            (p2, vars2) <- genPat vars1 sz'
            return (App p1 p2, vars2)
       , do (p1, vars1) <- genPat vars sz'
            i <- QC.elements [0 .. 5]
            return (Inj i p1, vars1)
       , do n <- QC.elements [0..3]
            (ps, vars') <- foldM (\(acc, v) _ -> do
                                    (p, v') <- genPat v sz'
                                    return (acc ++ [p], v'))
                                 ([], vars) [0..n]
            return (Pair ps, vars')
       ]
      where sz' = sz `div` 2

  
-- >>> QC.sample' (genTm 0 5)

-- | Generate a term with @vars@ variables in scope and depth bounded by @sz@
genTm vars sz =
    let
        sz' = sz `div` 2
        gens = [ do let v = varNames !! vars
                    body <- genTm (vars + 1) sz'
                    pure (Lam v body)
               , App <$> genTm vars sz' <*> genTm vars sz'
               , Pair <$> QC.listOf (genTm vars sz')
               , Inj <$> QC.elements [0,1] <*> genTm vars sz'
               , Case <$> genTm vars sz' <*> QC.listOf (genBranch vars sz')
               ]
        genBranch vars sz' = do
          (p, vars') <- genPat vars sz'
          body <- genTm vars' sz' 
          return (p, body)
    in
    case vars of
       0 -> if sz <= 1
               then pure (Pair [])     -- smallest closed term (unit)
               else QC.oneof gens
       _  -> if sz <= 1
                then QC.oneof [Var <$> genVar vars, pure (Pair [])]
                else QC.oneof ((Var <$> genVar vars) : gens)

-- | Shrink a named lambda calculus term, preserving scope
shrinkTm :: Tm -> [Tm]
shrinkTm (Var _)     = []
shrinkTm (Lam x t)   = [t] ++ [Lam x t' | t' <- shrinkTm t]
shrinkTm (App f a)   = [f, a] ++ [App f' a | f' <- shrinkTm f]
                                ++ [App f a' | a' <- shrinkTm a]
shrinkTm (Pair ts)   = [Pair ts' | ts' <- shrink ts]
shrinkTm (Inj i t)   = [t] ++ [Inj i t' | t' <- shrinkTm t]
shrinkTm (Case e bs) = [e] ++ [Case e' bs | e' <- shrinkTm e]
                           ++ [Case e bs' | bs' <- shrink bs]
shrinkTm (Ann t _)   = [t]

-- | Shrink a binary constructor by shrinking either child
shrinkTwo :: QC.Arbitrary a => (a -> a -> a) -> a -> a -> [a]
shrinkTwo f a b =
  [a,b] ++ [ f a' b | a' <- shrink a]
        ++ [ f a b' | b' <- shrink b]

-- | Shrink a binary constructor whose two arguments have different types
shrinkTwo' :: (QC.Arbitrary a, QC.Arbitrary b) => (a -> b -> a) -> a -> b -> [a]
shrinkTwo' f a b =
  [a] ++ [ f a' b | a' <- shrink a]
        ++ [ f a b' | b' <- shrink b]
